/**
 * Webhook notification handler — fires HTTP callbacks when order events occur.
 *
 * Architecture: Subscribes to order events via EventBus, consistent with
 * the codebase's event-driven notification pattern. External URLs are
 * registered for specific event types through the webhook registry.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, AppEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventTypes: EventType[];
  secret?: string;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: Record<string, unknown>;
  success: boolean;
  statusCode: number;
  deliveredAt: Date;
}

export type HttpClient = (
  url: string,
  options: { method: string; headers: Record<string, string>; body: string },
) => Promise<{ status: number }>;

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

export class WebhookNotificationHandler {
  private logger = new Logger('WebhookNotificationHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private httpClient: HttpClient;

  constructor(
    private eventBus: EventBus,
    httpClient?: HttpClient,
  ) {
    this.httpClient = httpClient ?? WebhookNotificationHandler.defaultHttpClient;
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on('order:created', (event) => {
      return this.deliverWebhooks('order:created', event);
    });

    this.eventBus.on('order:status-changed', (event) => {
      return this.deliverWebhooks('order:status-changed', event);
    });
  }

  /**
   * Register a webhook URL for specific event types.
   */
  registerWebhook(params: {
    url: string;
    eventTypes: EventType[];
    secret?: string;
  }): WebhookRegistration {
    if (!params.url) {
      throw new Error('Webhook URL is required');
    }
    if (params.eventTypes.length === 0) {
      throw new Error('At least one event type is required');
    }

    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url: params.url,
      eventTypes: params.eventTypes,
      secret: params.secret,
      createdAt: new Date(),
    };

    this.registrations.push(registration);
    this.logger.info(
      `Webhook registered: ${registration.id} -> ${params.url} for [${params.eventTypes.join(', ')}]`,
    );

    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index < 0) {
      return false;
    }
    this.registrations.splice(index, 1);
    this.logger.info(`Webhook unregistered: ${id}`);
    return true;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventTypes.includes(eventType));
  }

  /**
   * Get all delivery records.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clearAll(): void {
    this.registrations = [];
    this.deliveries = [];
  }

  private async deliverWebhooks(eventType: EventType, event: AppEvent): Promise<void> {
    const matching = this.registrations.filter((r) => r.eventTypes.includes(eventType));

    for (const registration of matching) {
      const payload: Record<string, unknown> = {
        event: eventType,
        data: event,
        timestamp: new Date().toISOString(),
      };

      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
      };
      if (registration.secret) {
        headers['X-Webhook-Secret'] = registration.secret;
      }

      let success = false;
      let statusCode = 0;

      try {
        const response = await this.httpClient(registration.url, {
          method: 'POST',
          headers,
          body: JSON.stringify(payload),
        });
        statusCode = response.status;
        success = statusCode >= 200 && statusCode < 300;
      } catch {
        this.logger.warn(
          `Webhook delivery failed for ${registration.id} to ${registration.url}`,
        );
      }

      const delivery: WebhookDelivery = {
        id: generateDeliveryId(),
        webhookId: registration.id,
        url: registration.url,
        eventType,
        payload,
        success,
        statusCode,
        deliveredAt: new Date(),
      };

      this.deliveries.push(delivery);
      this.logger.info(
        `Webhook delivered: ${delivery.id} to ${registration.url} (status: ${statusCode}, success: ${success})`,
      );
    }
  }

  private static async defaultHttpClient(
    _url: string,
    _options: { method: string; headers: Record<string, string>; body: string },
  ): Promise<{ status: number }> {
    return { status: 200 };
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookNotificationHandler,
  resetWebhookIdCounters,
} from '../../src/notifications/webhook-notification.handler.js';
import type { HttpClient } from '../../src/notifications/webhook-notification.handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('WebhookNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: WebhookNotificationHandler;
  let mockHttpClient: HttpClient;
  let httpCalls: Array<{ url: string; options: { method: string; headers: Record<string, string>; body: string } }>;

  beforeEach(() => {
    resetWebhookIdCounters();
    eventBus = new EventBus();
    httpCalls = [];
    mockHttpClient = vi.fn(async (url, options) => {
      httpCalls.push({ url, options });
      return { status: 200 };
    });
    handler = new WebhookNotificationHandler(eventBus, mockHttpClient);
  });

  describe('webhook registration', () => {
    it('should register a webhook for specific event types', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventTypes).toEqual(['order:created']);
      expect(handler.getRegistrations()).toHaveLength(1);
    });

    it('should register multiple webhooks', () => {
      handler.registerWebhook({
        url: 'https://example.com/hook1',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook2',
        eventTypes: ['order:status-changed'],
      });

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should register webhook with a secret', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'my-secret',
      });

      expect(reg.secret).toBe('my-secret');
    });

    it('should throw if URL is empty', () => {
      expect(() =>
        handler.registerWebhook({ url: '', eventTypes: ['order:created'] }),
      ).toThrow('Webhook URL is required');
    });

    it('should throw if event types are empty', () => {
      expect(() =>
        handler.registerWebhook({ url: 'https://example.com/hook', eventTypes: [] }),
      ).toThrow('At least one event type is required');
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });

    it('should filter registrations by event type', () => {
      handler.registerWebhook({
        url: 'https://example.com/hook1',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook2',
        eventTypes: ['order:status-changed'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook3',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(2);
    });
  });

  describe('webhook delivery on order:created', () => {
    it('should fire webhook when order is created', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(httpCalls).toHaveLength(1);
      expect(httpCalls[0]?.url).toBe('https://example.com/hook');
      expect(httpCalls[0]?.options.method).toBe('POST');
      expect(httpCalls[0]?.options.headers['Content-Type']).toBe('application/json');

      const body = JSON.parse(httpCalls[0]!.options.body);
      expect(body.event).toBe('order:created');
      expect(body.data.order.id).toBe('order-1');
    });

    it('should not fire webhook for unregistered event types', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 0,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(httpCalls).toHaveLength(0);
    });
  });

  describe('webhook delivery on order:status-changed', () => {
    it('should fire webhook when order status changes', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(httpCalls).toHaveLength(1);
      const body = JSON.parse(httpCalls[0]!.options.body);
      expect(body.event).toBe('order:status-changed');
      expect(body.data.previousStatus).toBe('pending');
      expect(body.data.newStatus).toBe('confirmed');
    });

    it('should fire multiple webhooks for the same event', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook1',
        eventTypes: ['order:status-changed'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook2',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      expect(httpCalls).toHaveLength(2);
      expect(httpCalls[0]?.url).toBe('https://example.com/hook1');
      expect(httpCalls[1]?.url).toBe('https://example.com/hook2');
    });
  });

  describe('webhook secret header', () => {
    it('should include secret header when secret is configured', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'my-secret-token',
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 0,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(httpCalls[0]?.options.headers['X-Webhook-Secret']).toBe('my-secret-token');
    });

    it('should not include secret header when no secret configured', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 0,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(httpCalls[0]?.options.headers['X-Webhook-Secret']).toBeUndefined();
    });
  });

  describe('delivery tracking', () => {
    it('should record successful deliveries', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(true);
      expect(deliveries[0]?.statusCode).toBe(200);
      expect(deliveries[0]?.eventType).toBe('order:status-changed');
    });

    it('should record failed deliveries on HTTP error', async () => {
      const failingClient: HttpClient = vi.fn(async () => ({ status: 500 }));
      const failHandler = new WebhookNotificationHandler(eventBus, failingClient);
      failHandler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const deliveries = failHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
      expect(deliveries[0]?.statusCode).toBe(500);
    });

    it('should record failed deliveries on network error', async () => {
      const errorClient: HttpClient = vi.fn(async () => {
        throw new Error('Network error');
      });
      const errorHandler = new WebhookNotificationHandler(eventBus, errorClient);
      errorHandler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const deliveries = errorHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
      expect(deliveries[0]?.statusCode).toBe(0);
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.registerWebhook({
        url: 'https://example.com/hook1',
        eventTypes: ['order:status-changed'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook2',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getDeliveriesForWebhook(reg1.id)).toHaveLength(1);
      expect(handler.getDeliveries()).toHaveLength(2);
    });
  });

  describe('integration with EventBus', () => {
    it('should coexist with other EventBus subscribers', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      const otherEvents: string[] = [];
      eventBus.on('order:status-changed', (event) => {
        otherEvents.push(event.type);
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      expect(handler.getDeliveries()).toHaveLength(1);
      expect(otherEvents).toHaveLength(1);
    });

    it('should handle full order lifecycle via webhooks', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 10,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(3);
      expect(deliveries[0]?.eventType).toBe('order:created');
      expect(deliveries[1]?.eventType).toBe('order:status-changed');
      expect(deliveries[2]?.eventType).toBe('order:status-changed');
    });
  });

  describe('clearAll', () => {
    it('should clear all registrations and deliveries', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      handler.clearAll();
      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveries()).toHaveLength(0);
    });
  });
});

