+      throw new Error('At least one event type is required');
+    }
+
+    const registration: WebhookRegistration = {
+      id: generateWebhookId(),
+      url: params.url,
+      eventTypes: params.eventTypes,
+      secret: params.secret,
+      createdAt: new Date(),
+    };
+
+    this.registrations.push(registration);
+    this.logger.info(
+      `Webhook registered: ${registration.id} -> ${params.url} for [${params.eventTypes.join(', ')}]`,
+    );
+
+    return registration;
+  }
+
+  /**
+   * Unregister a webhook by ID.
+   */
+  unregisterWebhook(id: string): boolean {
+    const index = this.registrations.findIndex((r) => r.id === id);
+    if (index < 0) {
+      return false;
+    }
+    this.registrations.splice(index, 1);
+    this.logger.info(`Webhook unregistered: ${id}`);
+    return true;
+  }
+
+  /**
+   * Get all registered webhooks.
+   */
+  getRegistrations(): WebhookRegistration[] {
+    return [...this.registrations];
+  }
+
+  /**
+   * Get registrations for a specific event type.
+   */
+  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
+    return this.registrations.filter((r) => r.eventTypes.includes(eventType));
+  }
+
+  /**
+   * Get all delivery records.
+   */
+  getDeliveries(): WebhookDelivery[] {
+    return [...this.deliveries];
+  }
+
+  /**
+   * Get deliveries for a specific webhook.
+   */
+  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
+    return this.deliveries.filter((d) => d.webhookId === webhookId);
+  }
+
+  /**
+   * Clear all registrations and deliveries (useful for testing).
+   */
+  clearAll(): void {
+    this.registrations = [];
+    this.deliveries = [];
+  }
+
+  private async deliverWebhooks(eventType: EventType, event: AppEvent): Promise<void> {
+    const matching = this.registrations.filter((r) => r.eventTypes.includes(eventType));
+
+    for (const registration of matching) {
+      const payload: Record<string, unknown> = {
+        event: eventType,
+        data: event,
+        timestamp: new Date().toISOString(),
+      };
+
+      const headers: Record<string, string> = {
+        'Content-Type': 'application/json',
+      };
+      if (registration.secret) {
+        headers['X-Webhook-Secret'] = registration.secret;
+      }
+
+      let success = false;
+      let statusCode = 0;
+
+      try {
+        const response = await this.httpClient(registration.url, {
+          method: 'POST',
+          headers,
+          body: JSON.stringify(payload),
+        });
+        statusCode = response.status;
+        success = statusCode >= 200 && statusCode < 300;
+      } catch {
+        this.logger.warn(
+          `Webhook delivery failed for ${registration.id} to ${registration.url}`,
+        );
+      }
+
+      const delivery: WebhookDelivery = {
+        id: generateDeliveryId(),
+        webhookId: registration.id,
+        url: registration.url,
+        eventType,
+        payload,
+        success,
+        statusCode,
+        deliveredAt: new Date(),
+      };
+
+      this.deliveries.push(delivery);
+      this.logger.info(
+        `Webhook delivered: ${delivery.id} to ${registration.url} (status: ${statusCode}, success: ${success})`,
+      );
+    }
+  }
+
+  private static async defaultHttpClient(
+    _url: string,
+    _options: { method: string; headers: Record<string, string>; body: string },
+  ): Promise<{ status: number }> {
+    return { status: 200 };
+  }
+}

